class Solution:
    def edgeScore(self, edges):
        n = len(edges)
        scores = [0] * n
        for i in range(n):
            scores[edges[i]] += i
        best_node = 0
        best_val = scores[0]
        for i in range(1, n):
            if scores[i] > best_val:
                best_val = scores[i]
                best_node = i
        return best_node

solutions.python:
class Solution:
    def edgeScore(self, edges):
        n = len(edges)
        scores = [0] * n
        for i, t in enumerate(edges):
            scores[t] += i
        return max(range(n), key=lambda i: (scores[i], -i))

