var edgeScore = function(edges) {
    const n = edges.length;
    const scores = new Array(n).fill(0);
    for (let i = 0; i < n; i++) scores[edges[i]] += i;
    let bestNode = 0, bestVal = scores[0];
    for (let i = 1; i < n; i++) {
        if (scores[i] > bestVal) { bestVal = scores[i]; bestNode = i; }
    }
    return bestNode;
};
